    edge [fontname="Helvetica"];

    subgraph cluster_eager_pre {
        label="Eager (pre-compilation)";
        style=dashed;
        color=gray;
        fontcolor=gray;

        systems [label="List[System]", fillcolor="#e8f4fd"];
        s2b [label="systems_to_batch()", fillcolor="#fff3cd"];
        batch [label="batch tensors\n(edge_vectors, indices,\npadding_mask, ...)", fillcolor="#e8f4fd"];
    }

    subgraph cluster_compiled {
        label="FX Compiled Graph\n(single torch.compile)";
        style=bold;
        color="#198754";
        fontcolor="#198754";

        edge_dist [label="edge_distances =\nsqrt(edge_vectors² + ε)", fillcolor="#d1e7dd"];
        swap_in [label="NamedMemberAccessor\nswap params in", fillcolor="#d1e7dd"];
        fwd [label="_forward_from_batch()\nGNN layers → heads → predictions", fillcolor="#d1e7dd"];
        scatter_e [label="scatter_add_\nper-atom → per-structure energy", fillcolor="#d1e7dd"];
        autograd [label="autograd.grad(\ncreate_graph=False)", fillcolor="#f8d7da"];
        forces [label="chain rule scatter\n→ per-atom forces", fillcolor="#f8d7da"];
        stress [label="virial einsum\n→ per-structure stress", fillcolor="#f8d7da"];
        swap_out [label="NamedMemberAccessor\nswap params out", fillcolor="#d1e7dd"];
    }

    subgraph cluster_eager_post {
        label="Eager (post-compilation)";
        style=dashed;
        color=gray;
        fontcolor=gray;

        wrap [label="_wrap_compiled_output()\n→ Dict[str, TensorMap]", fillcolor="#fff3cd"];
        avg [label="average_by_num_atoms()", fillcolor="#fff3cd"];
        loss [label="loss_fn(predictions, targets)", fillcolor="#fff3cd"];
        backward [label="loss.backward()\n(single backward)", fillcolor="#cfe2ff"];
        optim [label="optimizer.step()", fillcolor="#cfe2ff"];
    }

    systems -> s2b;
    s2b -> batch;
    batch -> edge_dist;
    batch -> swap_in;
    swap_in -> fwd;
    edge_dist -> fwd;
    fwd -> scatter_e;
    scatter_e -> autograd;
    autograd -> forces;
    autograd -> stress;
    fwd -> swap_out [style=dashed, label="restore"];
    forces -> wrap;
    stress -> wrap;
    scatter_e -> wrap;
    fwd -> wrap [label="raw_predictions"];
    wrap -> avg;
    avg -> loss;
    loss -> backward;
    backward -> optim;
}

